import{_ as t,o as i,c as l,a2 as o}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F17: 籌碼分佈與法人動態分析 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/4967_十銓/20260428/F17_籌碼分佈與法人動態分析_投資研究員.md","filePath":"審計報告庫/財務審計/4967_十銓/20260428/F17_籌碼分佈與法人動態分析_投資研究員.md"}'),e={name:"審計報告庫/財務審計/4967_十銓/20260428/F17_籌碼分佈與法人動態分析_投資研究員.md"};function r(n,a,s,c,h,_){return i(),l("div",null,[...a[0]||(a[0]=[o('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f17-籌碼分佈與法人動態分析-投資研究員-審計報告" tabindex="-1">F17: 籌碼分佈與法人動態分析 - 投資研究員 審計報告 <a class="header-anchor" href="#f17-籌碼分佈與法人動態分析-投資研究員-審計報告" aria-label="Permalink to &quot;F17: 籌碼分佈與法人動態分析 - 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>外資、投信與自營商的近期買賣超動向為何？千張大戶持股比例是否發生結構性變化？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：外資4月淨賣超~4千張，投信持續賣超，千張大戶持股從24.89%降至23.27%，融資暴增105%，散戶追漲形成「高位派發」格局，需警惕多殺多風險。</li><li><strong>風險評級</strong>：中高</li><li><strong>數據時效</strong>：根據截至2026年4月28日最新數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>：外資4月淨賣超~4千張；投信每日賣超合計-350張；千張大戶從24.89%降至23.27%（-1.62pp）；融資14,137張較年初增105%；融券歸零，借券1,530張</li><li><strong>診斷見解</strong>：三方角力：外資偏賣非恐慌、投信力道溫和、融資暴增反映散戶追漲。千張大戶減碼、散戶槓桿承接，為「籌碼從強勢手流向弱勢手」的派發初期特徵。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="法人動向與共識判定" tabindex="-1">法人動向與共識判定 <a class="header-anchor" href="#法人動向與共識判定" aria-label="Permalink to &quot;法人動向與共識判定&quot;">​</a></h3><ul><li><strong>核心重點</strong>：4月外資買超8天（+5,300張）、賣超10天（-9,300張），淨賣超約4,000張。3月淨買超約3,000張，3月底至4月轉為持續賣超。投信4月每交易日均賣超，無買超日。</li><li><strong>深度見解</strong>：外資從「3月買超→4月賣超」反映對十銓短線估值重估。4/10單日賣超2,723張以算法交易系統性減碼。投信全面賣超可能反映對Q1財報（5月公布）的預期管理。三大法人無共識性合力，股價缺乏機構買盤支撐。</li></ul><h3 id="籌碼集中度與散戶動態" tabindex="-1">籌碼集中度與散戶動態 <a class="header-anchor" href="#籌碼集中度與散戶動態" aria-label="Permalink to &quot;籌碼集中度與散戶動態&quot;">​</a></h3><ul><li><strong>核心重點</strong>：千張大戶12人從24.89%降至23.27%，人數不變但持股比例下降。400張以上34.61%，65.39%籌碼分散於中小型投資人。融資從3/10的6,885張飆升至4/24的14,137張（+105%），45天增7,252張。</li><li><strong>深度見解</strong>：融資暴增105%是最值得警惕的信號。3/10股價約209元至4/28漲至258.50元（+23.7%），融資同步翻倍，散戶以槓桿追漲。融資快速成長且千張大戶同步減碼，構成經典「派發型籌碼結構」。一旦股價回檔超過15-20%，融資斷頭壓力將加速下跌，形成多殺多惡性循環。融券歸零進一步消除軋空動能。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一</strong>：融資暴增105%疊加千張大戶減碼1.62pp，構成「散戶進、大戶退」的經典派發格局。若Q1財報顯示營收環比下滑或毛利率收窄，融資客心理防線將崩潰，14,137張融資（市值約36.5億元）的斷頭賣壓可能導致股價快速回測200元以下。建議以融資維持率130%為警戒線。</li><li><strong>空頭風險二</strong>：投信連續數週零買超且持續賣超，國內法人「投信鎖碼」格局已瓦解。在外資同步偏賣下，買盤完全依賴散戶融資與現股，一旦市場情緒轉弱，缺乏法人護盤的股票將面臨更大下行波動。十銓屬小型股，流動性有限，恐慌拋售時滑價風險更高。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: OK（法人買賣超、股權分散表）</li><li><strong>yfinance</strong>: 不適用</li><li><strong>年報/法說</strong>: 不適用（使用即時交易數據）</li><li><strong>關鍵核對碼</strong>： <ul><li>外資4/10賣超: 2,723張（wantgoo.com）</li><li>投信4/24賣超: 40張（wantgoo.com）</li><li>千張大戶4/24: 12人/23.27%（wantgoo.com）</li><li>融資餘額4/24: 14,137張（histock.tw）</li><li>借券賣出4/24: 1,530張（wantgoo.com）</li></ul></li></ul>',17)])])}const g=t(e,[["render",r]]);export{u as __pageData,g as default};
